previewCss:
.darma-loader-demo-dots {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  color: var(--loader-color, #6366f1);
}
.darma-loader-demo-dots span {
  width: 12px;
  height: 12px;
  border-radius: 999px;
  background: currentColor;
  animation: darma-loader-demo-dots-loader-bounce 0.75s ease-in-out infinite alternate;
}
.darma-loader-demo-dots span:nth-child(2) { animation-delay: 0.15s; }
.darma-loader-demo-dots span:nth-child(3) { animation-delay: 0.3s; }
@keyframes darma-loader-demo-dots-loader-bounce {
  from { transform: translateY(0); opacity: 0.55; }
  to { transform: translateY(-12px); opacity: 1; }
}

